mapper.select:
SELECT COUNT(*)
FROM REPORT r
WHERE
    (
        r.target_type = 'item'
        AND EXISTS (
            SELECT 1 FROM ITEM i
            WHERE i.item_no = r.target_no
            AND i.user_no = #{userNo}
        )
    )
    OR
    (
        r.target_type = 'board'
        AND EXISTS (
            SELECT 1 FROM BOARD_POST b
            WHERE b.board_no = r.target_no
            AND b.user_no = #{userNo}
        )
    )
    OR
    (
        r.target_type = 'reply'
        AND EXISTS (
            SELECT 1 FROM REPLY rp
            WHERE rp.reply_no = r.target_no
            AND rp.user_no = #{userNo}
        )
    )
